import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"로그 업로드","description":"문제를 해결하기 위해 로그를 업로드하는 방법을 알아보세요.","frontmatter":{"title":"로그 업로드","description":"문제를 해결하기 위해 로그를 업로드하는 방법을 알아보세요.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"ko_kr/1.20.4/players/troubleshooting/uploading-logs.md","filePath":"versions/1.20.4/translated/ko_kr/players/troubleshooting/uploading-logs.md","lastUpdated":1739538073000}`);var a={name:`ko_kr/1.20.4/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">로그 업로드 <a class="header-anchor" href="#h1" aria-label="Permalink to “로그 업로드”">​</a></h1><p>문제를 해결할 때, 원인을 파악하기 위해 개발자에게 로그를 전송해야 하는 경우가 자주 있습니다.</p><h2 id="로그를-업로드해야-하는-이유" tabindex="-1">로그를 업로드해야 하는 이유 <a class="header-anchor" href="#로그를-업로드해야-하는-이유" aria-label="Permalink to “로그를 업로드해야 하는 이유”">​</a></h2><p>로그를 단순히 복사-붙여넣기 하는것 보다 업로드하면 문제를 해결하는게 보다 수월해집니다. 또한 다른 곳으로 로그를 간단하게 전송할 수 있게 됩니다.</p><p>때때로 일부 서비스에서는 로그에 구문 강조를 지원하여, 더 쉽게 읽을 수 있게 하고, 사용자 아이디나 시스템 정보 등 민감한 정보를 걸러주기도 합니다.</p><h2 id="충돌-보고서" tabindex="-1">충돌 보고서 <a class="header-anchor" href="#충돌-보고서" aria-label="Permalink to “충돌 보고서”">​</a></h2><p>충돌 리포트는 게임이 충돌하면 자동으로 생성되며, 게임의 전체 로그 대신 충돌 관련 정보만 포함하고 있습니다. 충돌 리포트는 게임 디렉토리의 <code>crash-reports</code> 폴더에 저장됩니다.</p><p>충돌 리포트에 대한 자세한 정보는 <a href="./crash-reports">충돌 리포트</a> 페이지를 참고하세요.</p><h2 id="로그-찾기" tabindex="-1">로그 찾기 <a class="header-anchor" href="#로그-찾기" aria-label="Permalink to “로그 찾기”">​</a></h2><p>본 가이드는 공식 Minecraft 런처 (일반적으로 &quot;바닐라 런처&quot; 라고 불림) 를 위한 것이며, 서드파티 런처는 해당 런처의 문서를 확인해야 합니다.</p><p>로그는 게임 디렉토리의 <code>logs</code> 폴더에 저장됩니다. 각 운영체제에서 로그 폴더의 위치는 다음과 같습니다.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>최신 로그는 <code>latest.log</code> 에 저장되며, 이전 로그는 <code>연도-월-일_순서.log.gz</code> 의 이름 패턴으로 저장됩니다.</p><h2 id="로그-업로드" tabindex="-1">로그 업로드 <a class="header-anchor" href="#로그-업로드" aria-label="Permalink to “로그 업로드”">​</a></h2><p>로그는 다음처럼 여러 서비스로 업로드 될 수 있습니다.</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};